import { resetPasswordOptions, useAuth } from "@better-auth-ui/solid"
import { createMutation } from "@tanstack/solid-query"
import { createSignal, Show } from "solid-js"
import { Button } from "@/components/ui/button"
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"

export type ResetPasswordProps = {
  token?: string
}

const tokenFromLocation = () => {
  if (typeof window === "undefined") return undefined

  return new URLSearchParams(window.location.search).get("token") ?? undefined
}

export function ResetPassword(props: ResetPasswordProps) {
  const auth = useAuth()
  const [password, setPassword] = createSignal("")
  const [passwordError, setPasswordError] = createSignal<string>()
  const [confirmPassword, setConfirmPassword] = createSignal("")
  const [confirmPasswordError, setConfirmPasswordError] = createSignal<string>()
  const [tokenError, setTokenError] = createSignal<string>()
  const [isPasswordVisible, setIsPasswordVisible] = createSignal(false)
  const [isConfirmPasswordVisible, setIsConfirmPasswordVisible] =
    createSignal(false)
  const resetPassword = createMutation(() =>
    resetPasswordOptions(auth.authClient)
  )

  const submitPasswordReset = (event: SubmitEvent) => {
    event.preventDefault()
    const token = props.token ?? tokenFromLocation()

    setTokenError(
      token ? undefined : auth.localization.auth.invalidResetPasswordToken
    )
    setConfirmPasswordError(
      password() === confirmPassword()
        ? undefined
        : auth.localization.auth.passwordsDoNotMatch
    )

    if (!token || password() !== confirmPassword()) return

    resetPassword.mutate({ token, newPassword: password() })
  }

  return (
    <Card class="w-full max-w-sm">
      <CardHeader>
        <CardTitle class="text-xl font-semibold">
          {auth.localization.auth.resetPassword}
        </CardTitle>
      </CardHeader>

      <CardContent>
        <form aria-label="Reset password" onSubmit={submitPasswordReset}>
          <div class="flex flex-col gap-6">
            <div class="grid gap-3">
              <Label for="reset-password-new">
                {auth.localization.auth.newPassword}
              </Label>
              <div class="relative">
                <Input
                  aria-invalid={Boolean(passwordError())}
                  autocomplete="new-password"
                  class="pr-12"
                  id="reset-password-new"
                  maxLength={auth.emailAndPassword.maxPasswordLength}
                  minLength={auth.emailAndPassword.minPasswordLength}
                  name="password"
                  onInput={(event) => {
                    setPassword(event.currentTarget.value)
                    setPasswordError(undefined)
                    setConfirmPasswordError(undefined)
                  }}
                  onInvalid={(event) => {
                    event.preventDefault()
                    setPasswordError(event.currentTarget.validationMessage)
                  }}
                  placeholder={auth.localization.auth.newPasswordPlaceholder}
                  required
                  type={isPasswordVisible() ? "text" : "password"}
                  value={password()}
                />

                <Button
                  aria-label={
                    isPasswordVisible()
                      ? auth.localization.auth.hidePassword
                      : auth.localization.auth.showPassword
                  }
                  class="absolute right-1 top-1/2 -translate-y-1/2"
                  onClick={() => setIsPasswordVisible((visible) => !visible)}
                  size="icon-sm"
                  title={
                    isPasswordVisible()
                      ? auth.localization.auth.hidePassword
                      : auth.localization.auth.showPassword
                  }
                  type="button"
                  variant="ghost"
                >
                  <span class="text-xs">
                    {isPasswordVisible() ? "Hide" : "Show"}
                  </span>
                </Button>
              </div>

              <Show when={passwordError()}>
                {(message) => (
                  <p class="text-sm text-destructive" role="alert">
                    {message()}
                  </p>
                )}
              </Show>
            </div>
            <div class="grid gap-3">
              <Label for="reset-password-confirm">
                {auth.localization.auth.confirmPassword}
              </Label>
              <div class="relative">
                <Input
                  aria-invalid={Boolean(confirmPasswordError())}
                  autocomplete="new-password"
                  class="pr-12"
                  id="reset-password-confirm"
                  maxLength={auth.emailAndPassword.maxPasswordLength}
                  minLength={auth.emailAndPassword.minPasswordLength}
                  name="confirmPassword"
                  onInput={(event) => {
                    setConfirmPassword(event.currentTarget.value)
                    setConfirmPasswordError(undefined)
                  }}
                  onInvalid={(event) => {
                    event.preventDefault()
                    setConfirmPasswordError(
                      event.currentTarget.validationMessage
                    )
                  }}
                  placeholder={
                    auth.localization.auth.confirmPasswordPlaceholder
                  }
                  required
                  type={isConfirmPasswordVisible() ? "text" : "password"}
                  value={confirmPassword()}
                />

                <Button
                  aria-label={
                    isConfirmPasswordVisible()
                      ? auth.localization.auth.hidePassword
                      : auth.localization.auth.showPassword
                  }
                  class="absolute right-1 top-1/2 -translate-y-1/2"
                  onClick={() =>
                    setIsConfirmPasswordVisible((visible) => !visible)
                  }
                  size="icon-sm"
                  title={
                    isConfirmPasswordVisible()
                      ? auth.localization.auth.hidePassword
                      : auth.localization.auth.showPassword
                  }
                  type="button"
                  variant="ghost"
                >
                  <span class="text-xs">
                    {isConfirmPasswordVisible() ? "Hide" : "Show"}
                  </span>
                </Button>
              </div>

              <Show when={confirmPasswordError()}>
                {(message) => (
                  <p class="text-sm text-destructive" role="alert">
                    {message()}
                  </p>
                )}
              </Show>
            </div>
            <Button disabled={resetPassword.isPending} type="submit">
              {resetPassword.isPending
                ? `${auth.localization.auth.resetPassword}…`
                : auth.localization.auth.resetPassword}
            </Button>
            <Show when={tokenError()}>
              {(message) => <p role="alert">{message()}</p>}
            </Show>
            <Show when={resetPassword.isSuccess}>
              <p role="status">
                Password reset successfully. You can sign in with your new
                password.
              </p>
            </Show>
            <Show when={resetPassword.isError}>
              <p role="alert">Unable to reset your password. Try again.</p>
            </Show>
          </div>
        </form>

        <div class="mt-4 flex w-full flex-col items-center gap-3">
          <p class="text-center text-sm text-muted-foreground">
            {auth.localization.auth.rememberYourPassword}{" "}
            <a
              class="underline underline-offset-4"
              href={`${auth.basePaths.auth}/${auth.viewPaths.auth.signIn}`}
            >
              {auth.localization.auth.signIn}
            </a>
          </p>
        </div>
      </CardContent>
    </Card>
  )
}

import { type ButtonRootProps, Root } from "@kobalte/core/button"
import type { PolymorphicProps } from "@kobalte/core/polymorphic"
import { cva, type VariantProps } from "class-variance-authority"
import { type ComponentProps, splitProps, type ValidComponent } from "solid-js"
import { cn } from "@/lib/utils"

const buttonVariants = cva(
  "group/button z-button inline-flex shrink-0 select-none items-center justify-center whitespace-nowrap outline-none transition-all active:not-aria-[haspopup]:translate-y-px disabled:pointer-events-none disabled:opacity-50 [&_svg]:pointer-events-none [&_svg]:shrink-0",
  {
    variants: {
      variant: {
        default: "z-button-variant-default",
        outline: "z-button-variant-outline",
        secondary: "z-button-variant-secondary",
        ghost: "z-button-variant-ghost",
        destructive: "z-button-variant-destructive",
        link: "z-button-variant-link"
      },
      size: {
        default: "z-button-size-default",
        xs: "z-button-size-xs",
        sm: "z-button-size-sm",
        lg: "z-button-size-lg",
        icon: "z-button-size-icon",
        "icon-xs": "z-button-size-icon-xs",
        "icon-sm": "z-button-size-icon-sm",
        "icon-lg": "z-button-size-icon-lg"
      }
    },
    defaultVariants: {
      variant: "default",
      size: "default"
    }
  }
)

type ButtonProps<T extends ValidComponent = "button"> = PolymorphicProps<
  T,
  ButtonRootProps<T>
> &
  VariantProps<typeof buttonVariants> &
  Pick<ComponentProps<T>, "class">

const Button = <T extends ValidComponent = "button">(props: ButtonProps<T>) => {
  const [local, others] = splitProps(props as ButtonProps, [
    "variant",
    "size",
    "class"
  ])

  return (
    <Root
      class={cn(
        buttonVariants({ variant: local.variant, size: local.size }),
        local.class
      )}
      data-slot="button"
      {...others}
    />
  )
}

export { Button, type ButtonProps, buttonVariants }

import { type ComponentProps, mergeProps, splitProps } from "solid-js"

import { cn } from "@/lib/utils"

type CardProps = ComponentProps<"div"> & { size?: "default" | "sm" }

const Card = (props: CardProps) => {
  const mergedProps = mergeProps({ size: "default" } as const, props)
  const [local, others] = splitProps(mergedProps, ["class", "size"])

  return (
    <div
      class={cn("group/card z-card flex flex-col", local.class)}
      data-size={local.size}
      data-slot="card"
      {...others}
    />
  )
}

